const prospects = $input.first().json;
const now = new Date();

if (!Array.isArray(prospects) || prospects.length === 0) {
  return [{ json: { hasWork: false, summary: 'Нет активных проспектов', count: 0, prospectIds: [] } }];
}

const toProcess = [];
for (const p of prospects) {
  const nextFollowup = p.next_followup_at ? new Date(p.next_followup_at) : null;
  if (!nextFollowup || nextFollowup <= now) {
    toProcess.push(p);
  }
}

return [{ json: {
  hasWork: toProcess.length > 0,
  toProcess,
  prospectIds: toProcess.map(p => p.id),
  totalActive: prospects.length,
  totalToProcess: toProcess.length,
  summary: `Активных: ${prospects.length} / К обработке: ${toProcess.length}`
} }];

// ── RAG Outreach Message Builder with Conversation Context ──
const data = $('Analyze Prospects').first().json;
const toProcess = data.toProcess || [];
const allHistoryRaw = $('RAG: Fetch All Prospect History').first().json;
const allHistory = Array.isArray(allHistoryRaw) ? allHistoryRaw : [];

// Build per-prospect history lookup
const historyByProspect = {};
for (const m of allHistory) {
  if (!historyByProspect[m.entity_id]) historyByProspect[m.entity_id] = [];
  historyByProspect[m.entity_id].push(m);
}

const SPECIALTY_MAP = {
  demolition: 'снос и демонтаж',
  painting: 'малярно-штукатурные работы',
  electrical: 'электромонтаж',
  plumbing: 'сантехника',
  tiling: 'плитка',
  flooring: 'полы',
  carpentry: 'столярные работы',
  roofing: 'кровля',
  general: 'общестроительные',
  landscaping: 'благоустройство'
};

const contactMessages = [];
const inviteMessages = [];

for (const p of toProcess) {
  const city = p.city === 'novosibirsk' ? 'Новосибирске' : 'Омске';
  const specs = (p.specialties || []).map(s => SPECIALTY_MAP[s] || s).join(', ') || 'строительные работы';
  const history = historyByProspect[p.id] || [];
  const summary = p.conversation_summary || '';

  // RAG: Analyze conversation history for this prospect
  let lastInbound = '';
  let inboundCount = 0;
  let outboundCount = 0;
  for (const m of history) {
    if (m.direction === 'inbound') { lastInbound = m.message_text; inboundCount++; }
    else outboundCount++;
  }

  if (['new', 'messaged', 'replied'].includes(p.stage)) {
    let avitoMsg;
    if (p.stage === 'new' && outboundCount === 0) {
      // First contact — personalized intro
      avitoMsg = `Здравствуйте${p.name ? ', ' + p.name.split(' ')[0] : ''}! Меня зовут Алексей, я представляю сервис Подряд PRO — помогаем мастерам находить клиентов в ${city}.\n\nВижу, что вы занимаетесь ${specs}. У нас сейчас есть запросы от заказчиков именно по вашей специализации.\n\nПлатформа полностью бесплатна для исполнителей — вы получаете заказы и выбираете подходящие. Интересно?`;
    } else if (p.stage === 'new' && outboundCount > 0) {
      // Already wrote but stage wasn't updated
      avitoMsg = `Добрый день! Писал вам ранее по поводу сервиса Подряд PRO. У нас появились новые заказы по ${specs} в ${city}. Может, сейчас удобнее обсудить?`;
    } else if (p.stage === 'messaged') {
      // RAG: use history to personalize follow-up
      if (lastInbound) {
        avitoMsg = `Добрый день! Спасибо за ваш ответ. Вы писали: «${lastInbound.slice(0, 60)}»\n\nОтвечая на ваш вопрос — платформа полностью бесплатна, мы берём комиссию только с заказчиков. У нас сейчас есть заказы по ${specs}. Расскажу подробнее?`;
      } else {
        avitoMsg = `Добрый день! Писал вам ранее по поводу сервиса Подряд PRO. Хотел уточнить — получили моё сообщение? Появились актуальные заказы по ${specs} в ${city}.`;
      }
    } else if (p.stage === 'replied') {
      avitoMsg = `Отлично, что ответили! 🤝\n\n`;
      if (lastInbound) {
        avitoMsg += `По поводу вашего сообщения ("${lastInbound.slice(0, 60)}") — `;
      }
      avitoMsg += `Для регистрации на платформе нужно всего 5 минут. Могу прислать ссылку удобным способом — WhatsApp, Telegram или SMS. Как лучше?`;
    }
    contactMessages.push({
      ...p, avitoMessage: avitoMsg, action: 'avito_message',
      ragContext: `История: ${outboundCount} исх / ${inboundCount} вх`, inboundCount, outboundCount
    });
  }

  if (['contact_collected', 'invite_sent'].includes(p.stage)) {
    const regLink = `https://app.podryad.pro/join?ref=avito&phone=${p.phone || ''}`;
    let inviteMsg;
    if (p.stage === 'contact_collected') {
      inviteMsg = `🏗 Подряд PRO приглашает вас!\n\nВы общались с нашим представителем по поводу заказов в ${city}.`;
      if (lastInbound) {
        inviteMsg += `\nВы писали: «${lastInbound.slice(0, 60)}» — мы учли ваши пожелания!`;
      }
      inviteMsg += `\n\n✅ Регистрация бесплатная\n✅ Выбираете только подходящие заказы\n✅ Оплата гарантирована эскроу-сервисом\n\nЗарегистрироваться за 2 минуты: ${regLink}`;
    } else {
      inviteMsg = `Напоминаю о регистрации на Подряд PRO! Сейчас в системе есть ${Math.floor(Math.random() * 5 + 3)} заказов по ${specs} в ${city}.`;
      if (outboundCount > 3) {
        inviteMsg += `\n\nМы уже общались ${outboundCount} раз — видно, что вам это может быть интересно.`;
      }
      inviteMsg += `\n\nЗарегистрируйтесь — первый заказ подберём лично! 🤝\n${regLink}`;
    }
    inviteMessages.push({
      ...p, inviteMessage: inviteMsg, regLink, action: 'send_invite',
      ragContext: `История: ${outboundCount} исх / ${inboundCount} вх`, inboundCount, outboundCount
    });
  }
}

return [{ json: { contactMessages, inviteMessages, data } }];

const data = $input.first().json;
const contactMessages = data.contactMessages || [];
const inviteMessages = data.inviteMessages || [];

if (contactMessages.length === 0 && inviteMessages.length === 0) {
  return [{ json: { skipped: true, report: 'Нет проспектов для обработки' } }];
}

let report = `🤖 *CRM Агент — Исполнители Авито [RAG]*\nДата: ${new Date().toLocaleString('ru-RU')}\n`;
report += `📊 Обработано: ${data.data?.totalToProcess || 0} из ${data.data?.totalActive || 0}`;

if (contactMessages.length > 0) {
  report += `\n\n📨 *Написать в Авито (${contactMessages.length})*:`;
  for (const p of contactMessages.slice(0, 5)) {
    report += `\n\n👷 ${p.name || 'Без имени'} [${p.stage}]`;
    report += `\n📊 ${p.ragContext}`;
    if (p.avito_profile_url) report += `\n🔗 ${p.avito_profile_url}`;
    report += `\n\n*Текст:*\n${p.avitoMessage}`;
    report += `\n${'─'.repeat(20)}`;
  }
  if (contactMessages.length > 5) report += `\n...и ещё ${contactMessages.length - 5}`;
}

if (inviteMessages.length > 0) {
  report += `\n\n📲 *Отправить ссылку (${inviteMessages.length})*:`;
  for (const p of inviteMessages.slice(0, 5)) {
    report += `\n\n👷 ${p.name || 'Без имени'}${p.phone ? ' | ' + p.phone : ''}`;
    report += `\n📊 ${p.ragContext}`;
    if (p.email) report += `\n📧 Email: ${p.email}`;
    report += `\n\n*Текст:*\n${p.inviteMessage}`;
    report += `\n${'─'.repeat(20)}`;
  }
}

return [{ json: { report, contactMessages, inviteMessages, contactCount: contactMessages.length, inviteCount: inviteMessages.length } }];

// ── Log all generated messages to crm_messages + build stage updates ──
const data = $input.first().json;
const contactMessages = data.contactMessages || [];
const inviteMessages = data.inviteMessages || [];
const all = [...contactMessages, ...inviteMessages];
const now = new Date();

const logs = [];
const updates = [];

for (const p of all) {
  // Log the outreach message
  const msgText = p.avitoMessage || p.inviteMessage || '';
  if (msgText) {
    logs.push({
      entity_type: 'prospect',
      entity_id: p.id,
      direction: 'outbound',
      channel: p.action === 'avito_message' ? 'avito' : (p.email ? 'email' : 'avito'),
      message_text: msgText,
      is_automated: true,
      status: 'sent'
    });
  }

  // Build stage update with RAG summary
  let newStage = p.stage;
  let nextFollowup = null;
  if (p.stage === 'new') {
    newStage = 'messaged';
    nextFollowup = new Date(now.getTime() + 48 * 3600000).toISOString();
  } else if (p.stage === 'messaged') {
    nextFollowup = new Date(now.getTime() + 72 * 3600000).toISOString();
  } else if (p.stage === 'contact_collected') {
    newStage = 'invite_sent';
    nextFollowup = new Date(now.getTime() + 48 * 3600000).toISOString();
  } else if (p.stage === 'invite_sent') {
    nextFollowup = new Date(now.getTime() + 7 * 24 * 3600000).toISOString();
  }

  const summaryUpdate = `[${now.toISOString().slice(0,10)}] ` +
    `Stage: ${p.stage}→${newStage}. ` +
    `${p.ragContext}. ` +
    (p.action === 'avito_message' ? 'Авито-сообщение сгенерировано.' : 'Ссылка на регистрацию отправлена.');

  updates.push({
    id: p.id,
    stage: newStage,
    contact_attempts: (p.contact_attempts || 0) + 1,
    last_contacted_at: now.toISOString(),
    next_followup_at: nextFollowup,
    conversation_summary: summaryUpdate,
    updated_at: now.toISOString()
  });
}

return [{ json: { logs, updates, inviteMessages: data.inviteMessages } }];

// Split logs into individual items for batch insert
const { logs } = $input.first().json;
if (!logs || logs.length === 0) return [{ json: { skip: true } }];
return logs.map(l => ({ json: l }));

// Split updates into individual items
const { updates } = $('Build Updates + Logs').first().json;
if (!updates || updates.length === 0) return [{ json: { skip: true } }];
return updates.map(u => ({ json: u }));

// ── Email invites for prospects with email addresses ──
const data = $('Build Updates + Logs').first().json;
const invites = (data.inviteMessages || []).filter(p => p.email && p.email.trim());
if (invites.length === 0) return [{ json: { hasEmails: false, prospects: [] } }];
return [{ json: { hasEmails: true, prospects: invites } }];

const inviteSentProspects = $input.first().json;
if (!Array.isArray(inviteSentProspects) || inviteSentProspects.length === 0) {
  return [{ json: { phones: [], hasPhones: false } }];
}
const phones = inviteSentProspects.filter(p => p.phone).map(p => p.phone);
return [{ json: { toCheck: inviteSentProspects, phones, hasPhones: phones.length > 0 } }];

const registeredContractors = $input.first().json;
if (!Array.isArray(registeredContractors) || registeredContractors.length === 0) {
  return [{ json: { newlyRegistered: [], hasRegistered: false } }];
}
const now = new Date().toISOString();
// Return individual items for batch PATCH
return registeredContractors.map(c => ({ json: {
  phone: c.phone,
  contractor_id: c.id,
  stage: 'registered',
  registered_at: now,
  conversation_summary: `Зарегистрирован на платформе ${now.slice(0,10)}. Contractor ID: ${c.id}.`,
  updated_at: now
} }));

// Aggregate patched results and check if any were processed
const items = $input.all();
const phones = items.map(i => i.json.phone).filter(Boolean);
if (phones.length === 0) return [{ json: { hasRegistered: false, newlyRegistered: [] } }];
return [{ json: { hasRegistered: true, newlyRegistered: items.map(i => ({ phone: i.json.phone, id: i.json.contractor_id })) } }];

